"use client";

import { Loader2, Locate, Maximize, Minus, Plus } from "lucide-react";
import { useCallback, useState } from "react";

import { cn } from "@/lib/utils";
import { useLocale } from "@/lib/i18n";

import { useGeoMap } from "./mn-geo-map.helpers";
import {
  CompassButton,
  ControlButton,
  ControlGroup,
} from "./mn-geo-controls.helpers";

export interface MnGeoControlsProps {
  position?: "top-left" | "top-right" | "bottom-left" | "bottom-right";
  showZoom?: boolean;
  showCompass?: boolean;
  showLocate?: boolean;
  showFullscreen?: boolean;
  className?: string;
  onLocate?: (coords: { longitude: number; latitude: number }) => void;
}

const POSITION_CLASS: Record<NonNullable<MnGeoControlsProps["position"]>, string> = {
  "top-left": "top-2 left-2",
  "top-right": "top-2 right-2",
  "bottom-left": "bottom-2 left-2",
  "bottom-right": "bottom-10 right-2",
};

export function MnGeoControls({
  position = "bottom-right",
  showZoom = true,
  showCompass = false,
  showLocate = false,
  showFullscreen = false,
  className,
  onLocate,
}: MnGeoControlsProps) {
  const t = useLocale("geoMap");
  const { map } = useGeoMap();
  const [waiting, setWaiting] = useState(false);

  const zoomIn = useCallback(() => {
    map?.zoomTo(map.getZoom() + 1, { duration: 300 });
  }, [map]);
  const zoomOut = useCallback(() => {
    map?.zoomTo(map.getZoom() - 1, { duration: 300 });
  }, [map]);
  const resetBearing = useCallback(() => {
    map?.resetNorthPitch({ duration: 300 });
  }, [map]);

  const locate = useCallback(() => {
    if (!("geolocation" in navigator)) return;
    setWaiting(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const coords = {
          longitude: pos.coords.longitude,
          latitude: pos.coords.latitude,
        };
        map?.flyTo({
          center: [coords.longitude, coords.latitude],
          zoom: 14,
          duration: 1500,
        });
        onLocate?.(coords);
        setWaiting(false);
      },
      (err) => {
        console.error("MnGeoControls locate error:", err);
        setWaiting(false);
      },
    );
  }, [map, onLocate]);

  const fullscreen = useCallback(() => {
    const el = map?.getContainer();
    if (!el) return;
    if (document.fullscreenElement) {
      document.exitFullscreen();
    } else {
      el.requestFullscreen();
    }
  }, [map]);

  return (
    <div
      className={cn(
        "absolute z-10 flex flex-col gap-1.5",
        POSITION_CLASS[position],
        className,
      )}
    >
      {showZoom && (
        <ControlGroup>
          <ControlButton onClick={zoomIn} label={t.zoomIn}>
            <Plus className="size-4" aria-hidden />
          </ControlButton>
          <ControlButton onClick={zoomOut} label={t.zoomOut} isLast>
            <Minus className="size-4" aria-hidden />
          </ControlButton>
        </ControlGroup>
      )}
      {showCompass && (
        <ControlGroup>
          <CompassButton onClick={resetBearing} label={t.resetBearing} />
        </ControlGroup>
      )}
      {showLocate && (
        <ControlGroup>
          <ControlButton
            onClick={locate}
            label={t.findLocation}
            disabled={waiting}
            isLast
          >
            {waiting ? (
              <Loader2 className="size-4 animate-spin" aria-hidden />
            ) : (
              <Locate className="size-4" aria-hidden />
            )}
          </ControlButton>
        </ControlGroup>
      )}
      {showFullscreen && (
        <ControlGroup>
          <ControlButton
            onClick={fullscreen}
            label={t.toggleFullscreen}
            isLast
          >
            <Maximize className="size-4" aria-hidden />
          </ControlButton>
        </ControlGroup>
      )}
    </div>
  );
}

"use client";

import { useEffect, useRef, type ReactNode } from "react";

import { cn } from "@/lib/utils";

import { useGeoMap } from "./mn-geo-map.helpers";

export function ControlGroup({ children }: { children: ReactNode }) {
  return (
    <div
      className="flex flex-col overflow-hidden rounded-md"
      style={{
        background: "var(--mn-surface-raised)",
        border: "1px solid var(--mn-border)",
        boxShadow: "var(--shadow-sm)",
      }}
    >
      {children}
    </div>
  );
}

export function ControlButton({
  onClick,
  label,
  children,
  disabled = false,
  isLast,
}: {
  onClick: () => void;
  label: string;
  children: ReactNode;
  disabled?: boolean;
  isLast?: boolean;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      aria-label={label}
      disabled={disabled}
      className={cn(
        "flex size-8 items-center justify-center transition-colors",
        "first:rounded-t-md last:rounded-b-md",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-inset",
        "disabled:pointer-events-none disabled:opacity-50",
      )}
      style={{
        color: "var(--mn-text)",
        borderBottom: isLast ? undefined : "1px solid var(--mn-border)",
        // @ts-expect-error CSS custom property
        "--tw-ring-color": "var(--mn-focus-ring)",
      }}
      onMouseEnter={(e) => {
        if (!disabled) {
          (e.currentTarget as HTMLButtonElement).style.background =
            "var(--mn-hover-bg)";
        }
      }}
      onMouseLeave={(e) => {
        (e.currentTarget as HTMLButtonElement).style.background = "transparent";
      }}
    >
      {children}
    </button>
  );
}

export function CompassButton({
  onClick,
  label,
}: {
  onClick: () => void;
  label: string;
}) {
  const { map } = useGeoMap();
  const ref = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!map || !ref.current) return;
    const svg = ref.current;
    const update = () => {
      svg.style.transform = `rotateX(${map.getPitch()}deg) rotateZ(${-map.getBearing()}deg)`;
    };
    map.on("rotate", update);
    map.on("pitch", update);
    update();
    return () => {
      map.off("rotate", update);
      map.off("pitch", update);
    };
  }, [map]);

  return (
    <ControlButton onClick={onClick} label={label} isLast>
      <svg
        ref={ref}
        viewBox="0 0 24 24"
        className="size-5 transition-transform duration-200"
        style={{ transformStyle: "preserve-3d" }}
        aria-hidden
      >
        <path d="M12 2L16 12H12V2Z" style={{ fill: "var(--mn-error)" }} />
        <path
          d="M12 2L8 12H12V2Z"
          style={{
            fill: "color-mix(in srgb, var(--mn-error) 55%, transparent)",
          }}
        />
        <path
          d="M12 22L16 12H12V22Z"
          style={{
            fill: "color-mix(in srgb, var(--mn-text-muted) 60%, transparent)",
          }}
        />
        <path
          d="M12 22L8 12H12V22Z"
          style={{
            fill: "color-mix(in srgb, var(--mn-text-muted) 30%, transparent)",
          }}
        />
      </svg>
    </ControlButton>
  );
}
